const express = require('express');
const fs = require('fs');
const path = require('path');
const winston = require('winston');

const app = express();
app.set('trust proxy', true);

app.use(express.json({ limit: '1mb' }));
app.use(express.urlencoded({ extended: true }));

const logDir = process.env.LOG_DIR || path.join(__dirname, 'logs');
fs.mkdirSync(logDir, { recursive: true });

const auditLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.printf(({ timestamp, level, message }) => `${timestamp} ${level.toUpperCase()} ${message}`)
  ),
  transports: [
    new winston.transports.File({
      filename: path.join(logDir, 'audit.log'),
      maxsize: 10 * 1024 * 1024,
      maxFiles: 10
    })
  ]
});

function getClientIp(req) {
  const xff = req.headers['x-forwarded-for'];
  if (xff) return String(xff).split(',')[0].trim();
  return req.ip || req.connection?.remoteAddress || '';
}

function logRequest(req, extra = {}) {
  const username =
    req.headers['x-username'] ||
    req.query.username ||
    req.body?.username ||
    'anonymous';

  const ip = getClientIp(req);
  const customHeader = req.headers['x-audit-tag'] || req.headers['x-custom-header'] || '';

  const userInput = req.body?.message ?? req.query.message ?? '';
  const note = req.body?.note ?? req.query.note ?? '';

  const entry = {
    method: req.method,
    path: req.originalUrl,
    ip,
    username,
    customHeader,
    userAgent: req.headers['user-agent'] || '',
    referer: req.headers['referer'] || '',
    requestId: req.headers['x-request-id'] || '',
    userInput,
    note,
    ...extra
  };

  auditLogger.info(JSON.stringify(entry));
}

app.use((req, res, next) => {
  const start = Date.now();
  res.on('finish', () => {
    logRequest(req, {
      status: res.statusCode,
      durationMs: Date.now() - start,
      contentLength: res.getHeader('content-length') || ''
    });
  });
  next();
});

app.get('/', (req, res) => {
  res.type('text').send('ok');
});

app.post('/audit', (req, res) => {
  logRequest(req, { event: 'manual_audit', body: req.body });
  res.json({ ok: true });
});

app.get('/audit', (req, res) => {
  logRequest(req, { event: 'manual_audit_query', query: req.query });
  res.json({ ok: true });
});

app.post('/login', (req, res) => {
  const username = req.body?.username || req.query.username || 'anonymous';
  logRequest(req, { event: 'login_attempt', username, payload: req.body });
  res.json({ ok: true, username });
});

const port = Number(process.env.PORT || 3000);
app.listen(port, () => {
  auditLogger.info(JSON.stringify({ event: 'server_start', port, logDir }));
});